import java.io.*;
public class CustomSerial {
    static class Temp implements Serializable {
        double celsius;
        Temp(double c) { celsius = c; }
        private void writeObject(ObjectOutputStream out) throws IOException {
            out.writeDouble(celsius * 9.0/5.0 + 32);  // save as Fahrenheit
        }
        private void readObject(ObjectInputStream in) throws IOException, ClassNotFoundException {
            celsius = (in.readDouble() - 32) * 5.0/9.0;  // convert back
        }
    }
    public static void main(String[] args) throws Exception {
        Temp t = new Temp(100.0);
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        new ObjectOutputStream(baos).writeObject(t);
        Temp t2 = (Temp) new ObjectInputStream(
            new ByteArrayInputStream(baos.toByteArray())).readObject();
        System.out.println((int)t2.celsius);
    }
}
